import {LoadableApp} from "qiankun";

export function proxyConsole(global: typeof window, app: LoadableApp<any>){
    let _proxy_console: typeof console | null = null
    global.console = _proxy_console = _proxy_console ?? Object.create(global.console)
    _proxy_console!.log = global.console.log.bind(_proxy_console, `[${app.name}]:`)
    _proxy_console!.info = global.console.info.bind(_proxy_console, `[${app.name}]:`)
    _proxy_console!.debug = global.console.debug.bind(_proxy_console, `[${app.name}]:`)
    _proxy_console!.warn = global.console.warn.bind(_proxy_console, `[${app.name}]`)
    _proxy_console!.error = global.console.error.bind(_proxy_console, `[${app.name}]:`)
}